+      isSearchList: this.isSearchList,
+    })
+      .borderRadius(this.getBorderRadius())
+      .backgroundColor($r('sys.color.comp_background_list_card'))
+  }
+
+  private getBorderRadius(): BorderRadiuses {
+    const isFirst = this.index === 0;
+    const isLast = this.index === this.totalCount - 1;
+    const cornerRadius = $r('sys.float.corner_radius_level10');
+    return {
+      topLeft: isFirst ? cornerRadius : 0,
+      topRight: isFirst ? cornerRadius : 0,
+      bottomLeft: isLast ? cornerRadius : 0,
+      bottomRight: isLast ? cornerRadius : 0,
+    };
+  }
+}

